} from "firebase/firestore";
import { CalendarEvent } from "../types";

// Your web app's Firebase configuration
const firebaseConfig = {
  apiKey: "AIzaSyCw9kIH7GR5UaBS94tzP2ckNVS_yFtzJUg",
